__global__ void pgain_kernel(int start, int end, Point* d_p, int dim, bool* d_is_center, int* d_center_table, bool* d_switch_membership, double* d_lower, double* d_cost_of_opening_x, int x) {
    int i = blockIdx.x * blockDim.x + threadIdx.x + start;
    if (i >= end) return;

    float x_cost = 0.0f;
    for (int d_i = 0; d_i < dim; d_i++) {
        float diff = d_p[i].coord[d_i] - d_p[x].coord[d_i];
        x_cost += diff * diff;
    }
    x_cost *= d_p[i].weight;

    float current_cost = d_p[i].cost;

    if (x_cost < current_cost) {
        d_switch_membership[i] = true;
        atomicAdd(d_cost_of_opening_x, (double)(x_cost - current_cost));
    } else {
        int assign = d_p[i].assign;
        atomicAdd(&d_lower[d_center_table[assign]], (double)(current_cost - x_cost));
    }
}

__global__ void update_centers_kernel(int start, int end, bool* d_is_center, double* d_gl_lower, int* d_center_table) {
    int i = blockIdx.x * blockDim.x + threadIdx.x + start;
    if (i >= end) return;

    if (d_is_center[i]) {
        if (d_gl_lower[d_center_table[i]] > 0) {
            d_is_center[i] = false;
        }
    }
}

__global__ void update_assignments_kernel(int start, int end, Point* d_p, int dim, bool* d_switch_membership, bool* d_is_center, double* d_gl_lower, int* d_center_table, int x) {
    int i = blockIdx.x * blockDim.x + threadIdx.x + start;
    if (i >= end) return;

    bool close_center = d_gl_lower[d_center_table[d_p[i].assign]] > 0;
    if (d_switch_membership[i] || close_center) {
        float new_cost = 0.0f;
        for (int d_i = 0; d_i < dim; d_i++) {
            float diff = d_p[i].coord[d_i] - d_p[x].coord[d_i];
            new_cost += diff * diff;
        }
        d_p[i].cost = d_p[i].weight * new_cost;
        d_p[i].assign = x;
    }
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE
  double t0 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  int number_of_centers_to_close = 0;

  int stride = *numcenters+2;
  int cl = CACHE_LINE/sizeof(double);
  if( stride % cl != 0 ) { 
    stride = cl * ( stride / cl + 1);
  }
  int K = stride -2 ; 

  double cost_of_opening_x = 0;

  static double *work_mem = NULL;
  static double gl_cost_of_opening_x = 0;
  static int gl_number_of_centers_to_close = 0;

  if( pid==0 ) { 
    work_mem = (double*) malloc(stride*(nproc+1)*sizeof(double));
    gl_cost_of_opening_x = 0;
    gl_number_of_centers_to_close = 0;
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  int count = 0;
  for( int i = k1; i < k2; i++ ) {
    if( is_center[i] ) {
      center_table[i] = count++;
    }
  }
  work_mem[pid*stride] = count;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 ) {
    int accum = 0;
    for( int p = 0; p < nproc; p++ ) {
      int tmp = (int)work_mem[p*stride];
      work_mem[p*stride] = accum;
      accum += tmp;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for( int i = k1; i < k2; i++ ) {
    if( is_center[i] ) {
      center_table[i] += (int)work_mem[pid*stride];
    }
  }

  memset(switch_membership + k1, 0, (k2-k1)*sizeof(bool));
  memset(work_mem+pid*stride, 0, stride*sizeof(double));
  if( pid== 0 ) memset(work_mem+nproc*stride,0,stride*sizeof(double));

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
#ifdef PROFILE
  double t1 = gettime();
  if( pid == 0 ) time_gain_init += t1-t0;
#endif

  double* lower = &work_mem[pid*stride];
  double* gl_lower = &work_mem[nproc*stride];

  // Allocate device memory for points and arrays
  Point* d_p;
  bool* d_is_center;
  int* d_center_table;
  bool* d_switch_membership;
  double* d_lower;
  double* d_cost_of_opening_x;

  cudaMalloc((void**)&d_p, points->num * sizeof(Point));
  cudaMalloc((void**)&d_is_center, points->num * sizeof(bool));
  cudaMalloc((void**)&d_center_table, points->num * sizeof(int));
  cudaMalloc((void**)&d_switch_membership, points->num * sizeof(bool));
  cudaMalloc((void**)&d_lower, stride * sizeof(double));
  cudaMalloc((void**)&d_cost_of_opening_x, sizeof(double));

  cudaMemcpy(d_p, points->p, points->num * sizeof(Point), cudaMemcpyHostToDevice);
  cudaMemcpy(d_is_center, is_center, points->num * sizeof(bool), cudaMemcpyHostToDevice);
  cudaMemcpy(d_center_table, center_table, points->num * sizeof(int), cudaMemcpyHostToDevice);
  cudaMemset(d_switch_membership, 0, points->num * sizeof(bool));
  cudaMemset(d_lower, 0, stride * sizeof(double));
  cudaMemset(d_cost_of_opening_x, 0, sizeof(double));

  int threadsPerBlock = 256;
  int blocksPerGrid = (k2 - k1 + threadsPerBlock - 1) / threadsPerBlock;

  pgain_kernel<<<blocksPerGrid, threadsPerBlock>>>(k1, k2, d_p, points->dim, d_is_center, d_center_table, d_switch_membership, d_lower, d_cost_of_opening_x, (int)x);
  cudaDeviceSynchronize();

  cudaMemcpy(lower, d_lower, stride * sizeof(double), cudaMemcpyDeviceToHost);
  double cost_opening_x_host;
  cudaMemcpy(&cost_opening_x_host, d_cost_of_opening_x, sizeof(double), cudaMemcpyDeviceToHost);

  for ( int i = k1; i < k2; i++ ) {
    if( is_center[i] ) {
      double low = z;
      for( int p = 0; p < nproc; p++ ) {
        low += work_mem[center_table[i]+p*stride];
      }
      gl_lower[center_table[i]] = low;
      if ( low > 0 ) {
        ++number_of_centers_to_close;  
        cost_of_opening_x -= low;
      }
    }
  }

  work_mem[pid*stride + K] = number_of_centers_to_close;
  work_mem[pid*stride + K+1] = cost_of_opening_x;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid==0 ) {
    gl_cost_of_opening_x = z;
    for( int p = 0; p < nproc; p++ ) {
      gl_number_of_centers_to_close += (int)work_mem[p*stride + K];
      gl_cost_of_opening_x += work_mem[p*stride+K+1];
    }
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if ( gl_cost_of_opening_x < 0 ) {
    // Copy gl_lower to device
    double* d_gl_lower;
    cudaMalloc((void**)&d_gl_lower, stride * sizeof(double));
    cudaMemcpy(d_gl_lower, gl_lower, stride * sizeof(double), cudaMemcpyHostToDevice);

    update_assignments_kernel<<<blocksPerGrid, threadsPerBlock>>>(k1, k2, d_p, points->dim, d_switch_membership, d_is_center, d_gl_lower, d_center_table, (int)x);
    cudaDeviceSynchronize();

    update_centers_kernel<<<blocksPerGrid, threadsPerBlock>>>(k1, k2, d_is_center, d_gl_lower, d_center_table);
    cudaDeviceSynchronize();

    cudaMemcpy(is_center + k1, d_is_center + k1, (k2 - k1) * sizeof(bool), cudaMemcpyDeviceToHost);
    cudaMemcpy(points->p + k1, d_p + k1, (k2 - k1) * sizeof(Point), cudaMemcpyDeviceToHost);

    if( x >= k1 && x < k2 ) {
      is_center[x] = true;
    }

    if( pid==0 ) {
      *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
    }

    cudaFree(d_gl_lower);
  }
  else {
    if( pid==0 )
      gl_cost_of_opening_x = 0;  
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( pid == 0 ) {
    free(work_mem);
  }

  cudaFree(d_p);
  cudaFree(d_is_center);
  cudaFree(d_center_table);
  cudaFree(d_switch_membership);
  cudaFree(d_lower);
  cudaFree(d_cost_of_opening_x);

#ifdef PROFILE
  double t3 = gettime();
  if( pid==0 )
  time_gain += t3-t0;
#endif
  return -gl_cost_of_opening_x;
}

