      float diff = points->p[k].coord[dim_i] - points->p[0].coord[dim_i];
      distance += diff * diff;
    }
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign=0;
  }

  if( pid==0 )   {
    *kcenter = 1;
    costs = (double*)malloc(sizeof(double)*nproc);
  }

  if( pid != 0 ) { 
    while(1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while(!open) pthread_cond_wait(&cond,&mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if( i >= points->num ) break;
      for( int k = k1; k < k2; k++ )
	{
	  float distance = 0.0f;
	  for (int dim_i = 0; dim_i < points->dim; dim_i++) {
	    float diff = points->p[i].coord[dim_i] - points->p[k].coord[dim_i];
	    distance += diff * diff;
	  }
